#!/usr/bin/env python
"""Test script to reproduce the seaborn-colorblind issue"""
import sys
sys.path.insert(0, './swebench_9_15/testbed/lib')

import matplotlib.pyplot as plt

print("Testing access to seaborn-colorblind style...")
try:
    the_rc = plt.style.library["seaborn-colorblind"]
    print("SUCCESS: seaborn-colorblind is accessible")
    print(f"Type: {type(the_rc)}")
except KeyError as e:
    print(f"FAILED: KeyError - {e}")
    print(f"Available seaborn styles in library:")
    for key in sorted(plt.style.library.keys()):
        if 'seaborn' in key:
            print(f"  - {key}")

